package unverified;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairGenericInvocationTestSupport.*;

class ClonePair4130DifferenceFindingTest {

    private final ClonePair4130 subject = new ClonePair4130();

    /**
     * Generated by Codex (GPT-5.5).
     * Difference type: return_value.
     * Difference manifestation: the methods return different values.
     */
    @Test
    @BehavioralDifference(DifferenceType.RETURN_VALUE)
    void methodsDisagreeOnGeneratedInput() {
        Object[] inputs = new Object[]{Double.NEGATIVE_INFINITY, Double.NaN};
        InvocationOutcome method1Outcome = capture(values -> subject.method1(((Double) values[0]).doubleValue(), ((Double) values[1]).doubleValue()), inputs);
        InvocationOutcome method2Outcome = capture(values -> subject.method2(((Double) values[0]).doubleValue(), ((Double) values[1]).doubleValue()), inputs);

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "Double(-Infinity)",
            null,
            "java.lang.Object[][Double(-Infinity),Double(NaN)]",
            "java.lang.Object[][Double(-Infinity),Double(NaN)]"
        );
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "Double(NaN)",
            null,
            "java.lang.Object[][Double(-Infinity),Double(NaN)]",
            "java.lang.Object[][Double(-Infinity),Double(NaN)]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertTextEquals("stderr", "", method2Outcome.stderr);
        assertDifferent(method1Outcome, method2Outcome);
    }
}
